INSERT INTO `problem` VALUES (24, NULL, '1', '1', 1, '[]', '[]', 1000, 256, 0, 0, 0, '2026-05-08 14:23:10', '2026-05-08 06:23:12', 1);
INSERT INTO `problem_solution` VALUES (22, 1, 3, '两数之和', '利用哈希表进行“边走边记”的反向匹配。它通过一次遍历数组，将每个数字及其索引存入哈希表；在存入之前，先去表中查找是否存在能与当前数字凑成目标值的“另一半”。这种做法将传统双重循环O(N^2)的搜索时间，通过空间换时间的方式优化到了O(N)，即在一次扫描中就能锁定答案。', 'import java.util.*;\r\nimport java.io.*;\r\n\r\npublic class Solution {\r\n\r\n    /**\r\n     * 核心算法逻辑写在这里\r\n     */\r\n    public int[] solve(int[] nums, int target) {\r\n        Map<Integer, Integer> map = new HashMap<>();\r\n        for (int i = 0; i < nums.length; i++) {\r\n            int complement = target - nums[i];\r\n            if (map.containsKey(complement)) {\r\n                return new int[] { map.get(complement), i };\r\n            }\r\n            map.put(nums[i], i);\r\n        }\r\n        return new int[0];\r\n    }\r\n\r\n    /**\r\n     * CodeNexus ACM 模式程序入口\r\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\r\n     */\r\n    public static void main(String[] args) {\r\n        Scanner scanner = new Scanner(System.in);\r\n        \r\n        // 假设输入格式示例：\r\n        // [2,7,11,15]\r\n        // 9\r\n        if (scanner.hasNextLine()) {\r\n            // 1. 读取并解析输入数据\r\n            String line = scanner.nextLine().trim();\r\n            // 去除前后方括号\r\n            line = line.replace(\"[\", \"\").replace(\"]\", \"\");\r\n            String[] parts = line.split(\",\");\r\n            int[] nums = new int[parts.length];\r\n            for (int i = 0; i < parts.length; i++) {\r\n                nums[i] = Integer.parseInt(parts[i].trim());\r\n            }\r\n            \r\n            int target = Integer.parseInt(scanner.nextLine().trim());\r\n            \r\n            // 2. 实例化并调用核心算法\r\n            Solution sol = new Solution();\r\n            int[] result = sol.solve(nums, target);\r\n            \r\n            // 3. 按照题目要求的格式打印输出\r\n            if (result.length == 2) {\r\n                System.out.println(\"[\" + result[0] + \",\" + result[1] + \"]\");\r\n            } else {\r\n                System.out.println(\"[]\");\r\n            }\r\n        }\r\n        scanner.close();\r\n    }\r\n}', 1432, '2026-04-03 04:10:27', '2026-04-03 19:38:17', 0, 0);
INSERT INTO `problem_solution` VALUES (23, 2, 3, '爬楼梯', '### 解题思路\n\n爬楼梯问题是经典的动态规划问题，本质上也是斐波那契数列问题。\n\n1. 假设爬到第 n 阶有 f(n) 种方法。\n2. 因为每次只能爬 1 阶或 2 阶，所以到达第 n 阶的最后一步只有两种情况：要么是从第 n-1 阶跨 1 步上来，要么是从第 n-2 阶跨 2 步上来。\n3. 因此，状态转移方程为：f(n) = f(n-1) + f(n-2)。\n4. 边界条件为：f(1) = 1，f(2) = 2。\n5. 为了优化空间复杂度，我们可以不使用数组，而是只用两个变量来交替存储前两项的状态，这样可以将空间复杂度从 O(n) 降至 O(1)。', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public int solve(int n) {\n        if (n <= 2) {\n            return n;\n        }\n        \n        int prev1 = 1; // 相当于 dp[i-2]\n        int prev2 = 2; // 相当于 dp[i-1]\n        int current = 0; // 相当于 dp[i]\n        \n        for (int i = 3; i <= n; i++) {\n            current = prev1 + prev2;\n            prev1 = prev2;\n            prev2 = current;\n        }\n        \n        return current;\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        if (scanner.hasNextInt()) {\n            // 1. 读取并解析输入数据\n            int n = scanner.nextInt();\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            int result = sol.solve(n);\n            \n            // 3. 按照题目要求的格式打印输出\n            System.out.println(result);\n        }\n        \n        scanner.close();\n    }\n}', 1674, '2026-04-03 04:12:25', '2026-05-06 15:03:38', 0, 0);
INSERT INTO `problem_solution` VALUES (24, 3, 3, '有效的括号', '### 解题思路\r\n\r\n判断括号的有效性是**栈（Stack）**数据结构的经典应用场景。因为括号具有“后进先出”的对称匹配特性。\r\n\r\n1. **初始化栈**：我们可以遍历给定的字符串 `s`。\r\n2. **遇到左括号**：如果遇到 `(`、`{`、`[`，我们将它们直接压入栈中。\r\n3. **遇到右括号**：如果遇到 `)`、`}`、`]`，我们需要判断此时栈是否为空：\r\n   - 如果栈为空，说明没有多余的左括号来匹配当前的右括号，返回 `false`。\r\n   - 如果栈不为空，弹出栈顶元素，判断栈顶的左括号是否和当前的右括号类型匹配。如果不匹配，也返回 `false`。\r\n4. **遍历结束**：当字符串遍历完成后，如果栈为空，说明所有括号都已经正确匹配并闭合，返回 `true`；如果栈中还有未匹配的左括号，说明闭合不完整，返回 `false`。\r\n\r\n### 代码实现\r\n\r\n```java\r\nimport java.util.*;\r\nimport java.io.*;\r\n\r\npublic class Solution {\r\n\r\n    /**\r\n     * 核心算法逻辑写在这里\r\n     */\r\n    public boolean solve(String s) {\r\n        Stack<Character> stack = new Stack<>();\r\n        for (char c : s.toCharArray()) {\r\n            // 遇到左括号入栈\r\n            if (c == \'(\' || c == \'{\' || c == \'[\') {\r\n                stack.push(c);\r\n            } \r\n            // 遇到右括号进行匹配\r\n            else {\r\n                if (stack.isEmpty()) {\r\n                    return false;\r\n                }\r\n                char top = stack.pop();\r\n                if ((c == \')\' && top != \'(\') ||\r\n                    (c == \'}\' && top != \'{\') ||\r\n                    (c == \']\' && top != \'[\')) {\r\n                    return false;\r\n                }\r\n            }\r\n        }\r\n        // 最终检查栈是否为空\r\n        return stack.isEmpty();\r\n    }\r\n\r\n    /**\r\n     * CodeNexus ACM 模式程序入口\r\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\r\n     */\r\n    public static void main(String[] args) {\r\n        Scanner scanner = new Scanner(System.in);\r\n        \r\n        if (scanner.hasNextLine()) {\r\n            // 1. 读取并解析输入数据\r\n            String s = scanner.nextLine().trim();\r\n            \r\n            // 处理输入可能包含的双引号 (例如 s = \"()[]{}\")\r\n            if (s.startsWith(\"\"\") && s.endsWith(\"\"\")) {\r\n                s = s.substring(1, s.length() - 1);\r\n            }\r\n            \r\n            // 2. 实例化并调用核心算法\r\n            Solution sol = new Solution();\r\n            boolean result = sol.solve(s);\r\n            \r\n            // 3. 按照题目要求的格式打印输出\r\n            System.out.println(result);\r\n        }\r\n        \r\n        scanner.close();\r\n    }\r\n}\r\n```', NULL, 1107, '2026-04-03 04:14:54', '2026-05-08 20:19:21', 1, 0);
INSERT INTO `problem_solution` VALUES (25, 3, 3, '有效的括号', '### 解题思路\n\n判断括号的有效性是**栈（Stack）**数据结构的经典应用场景。因为括号具有“后进先出”的对称匹配特性。\n\n1. **初始化栈**：我们可以遍历给定的字符串 `s`。\n2. **遇到左括号**：如果遇到 `(`、`{`、`[`，我们将它们直接压入栈中。\n3. **遇到右括号**：如果遇到 `)`、`}`、`]`，我们需要判断此时栈是否为空：\n   - 如果栈为空，说明没有多余的左括号来匹配当前的右括号，返回 `false`。\n   - 如果栈不为空，弹出栈顶元素，判断栈顶的左括号是否和当前的右括号类型匹配。如果不匹配，也返回 `false`。\n4. **遍历结束**：当字符串遍历完成后，如果栈为空，说明所有括号都已经正确匹配并闭合，返回 `true`；如果栈中还有未匹配的左括号，说明闭合不完整，返回 `false`。', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public boolean solve(String s) {\n        Stack<Character> stack = new Stack<>();\n        for (char c : s.toCharArray()) {\n            // 遇到左括号入栈\n            if (c == \'(\' || c == \'{\' || c == \'[\') {\n                stack.push(c);\n            } \n            // 遇到右括号进行匹配\n            else {\n                if (stack.isEmpty()) {\n                    return false;\n                }\n                char top = stack.pop();\n                if ((c == \')\' && top != \'(\') ||\n                    (c == \'}\' && top != \'{\') ||\n                    (c == \']\' && top != \'[\')) {\n                    return false;\n                }\n            }\n        }\n        // 最终检查栈是否为空\n        return stack.isEmpty();\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        if (scanner.hasNextLine()) {\n            // 1. 读取并解析输入数据\n            String s = scanner.nextLine().trim();\n            \n            // 处理输入可能包含的双引号，注意此处已在 SQL 中将 Java 的 \\\" 转义为 \\\\\\\"\n            if (s.startsWith(\"\\\"\") && s.endsWith(\"\\\"\")) {\n                s = s.substring(1, s.length() - 1);\n            }\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            boolean result = sol.solve(s);\n            \n            // 3. 按照题目要求的格式打印输出\n            System.out.println(result);\n        }\n        \n        scanner.close();\n    }\n}', 1207, '2026-04-03 04:16:16', '2026-05-08 12:19:08', 0, 0);
INSERT INTO `problem_solution` VALUES (26, 1, 2, '测试', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public int[] solve(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        return new int[0];\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 假设输入格式示例：\n        // [2,7,11,15]\n        // 9\n        if (scanner.hasNextLine()) {\n            // 1. 读取并解析输入数据\n            String line = scanner.nextLine().trim();\n            // 去除前后方括号\n            line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n            String[] parts = line.split(\",\");\n            int[] nums = new int[parts.length];\n            for (int i = 0; i < parts.length; i++) {\n                nums[i] = Integer.parseInt(parts[i].trim());\n            }\n            \n            int target = Integer.parseInt(scanner.nextLine().trim());\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            int[] result = sol.solve(nums, target);\n            \n            // 3. 按照题目要求的格式打印输出\n            if (result.length == 2) {\n                System.out.println(\"[\" + result[0] + \",\" + result[1] + \"]\");\n            } else {\n                System.out.println(\"[]\");\n            }\n        }\n        scanner.close();\n    }\n}', NULL, 2, '2026-04-04 01:36:42', '2026-04-04 03:03:27', 1, 0);
