INSERT INTO `problem_submission` VALUES (4, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\n\nclass Solution {\n    public int[] twoSum(int[] nums, int target) {\n        // 创建一个哈希表，Key 存储数值，Value 存储对应的数组下标\n        Map<Integer, Integer> map = new HashMap<>();\n        \n        for (int i = 0; i < nums.length; i++) {\n            // 计算当前数字需要的“补数”\n            int complement = target - nums[i];\n            \n            // 如果哈希表中已经存在这个补数，说明找到了答案\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            \n            // 如果没找到，将当前数字和下标存入表，供后续数字匹配\n            map.put(nums[i], i);\n        }\n        \n        // 题目假设一定有答案，如果执行到这里说明输入有问题\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 0, NULL, NULL, '2026-03-29 05:47:48', '2026-03-29 05:47:48', 0);
