INSERT INTO `problem_submission` VALUES (7, 3, 1, 'java', '// 在这里开始你的编码...\nimport java.util.HashMap;\nimport java.util.Map;\n\nclass Solution {\n    public int[] twoSum(int[] nums, int target) {\n        // 创建一个哈希表，Key 存储数值，Value 存储对应的数组下标\n        Map<Integer, Integer> map = new HashMap<>();\n        \n        for (int i = 0; i < nums.length; i++) {\n            // 计算当前数字需要的“补数”\n            int complement = target - nums[i];\n            \n            // 如果哈希表中已经存在这个补数，说明找到了答案\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            \n            // 如果没找到，将当前数字和下标存入表，供后续数字匹配\n            map.put(nums[i], i);\n        }\n        \n        // 题目假设一定有答案，如果执行到这里说明输入有问题\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 5, 1033, 0.00, '2026-03-29 06:04:22', '2026-03-29 06:04:22', 0);
INSERT INTO `problem_submission` VALUES (8, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\nimport java.util.Arrays;\n\npublic class Solution {\n    \n    // 必须要有的主函数，用于接收沙箱喂进来的标准输入\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n        \n        // 1. 读取第一行：数组元素 (例如 \"2 7 11 15\")\n        String[] numsStr = scanner.nextLine().trim().split(\" \");\n        int[] nums = new int[numsStr.length];\n        for (int i = 0; i < numsStr.length; i++) {\n            nums[i] = Integer.parseInt(numsStr[i]);\n        }\n        \n        // 2. 读取第二行：目标值 (例如 9)\n        int target = scanner.nextInt();\n        \n        // 3. 调用你完美的核心算法\n        Solution sol = new Solution();\n        int[] result = sol.twoSum(nums, target);\n        \n        // 4. 将结果转为字符串打印到控制台，供沙箱抓取并与 Expected Output 对比\n        // Arrays.toString(result) 会打印出 \"[0, 1]\"，恰好与我们数据库里的格式完美匹配！\n        System.out.println(Arrays.toString(result));\n    }\n\n    // 你原来的核心算法代码，一字未改\n    public int[] twoSum(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 5, 1048, 0.00, '2026-03-29 06:08:15', '2026-03-29 06:08:15', 0);
INSERT INTO `problem_submission` VALUES (9, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\nimport java.util.Arrays;\n\npublic class Solution {\n    \n    // 必须要有的主函数，用于接收沙箱喂进来的标准输入\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n        \n        // 1. 读取第一行：数组元素 (例如 \"2 7 11 15\")\n        String[] numsStr = scanner.nextLine().trim().split(\" \");\n        int[] nums = new int[numsStr.length];\n        for (int i = 0; i < numsStr.length; i++) {\n            nums[i] = Integer.parseInt(numsStr[i]);\n        }\n        \n        // 2. 读取第二行：目标值 (例如 9)\n        int target = scanner.nextInt();\n        \n        // 3. 调用你完美的核心算法\n        Solution sol = new Solution();\n        int[] result = sol.twoSum(nums, target);\n        \n        // 4. 将结果转为字符串打印到控制台，供沙箱抓取并与 Expected Output 对比\n        // Arrays.toString(result) 会打印出 \"[0, 1]\"，恰好与我们数据库里的格式完美匹配！\n        System.out.println(Arrays.toString(result));\n    }\n\n    // 你原来的核心算法代码，一字未改\n    public int[] twoSum(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 5, 1158, 0.00, '2026-03-29 06:08:37', '2026-03-29 06:08:37', 0);
INSERT INTO `problem_submission` VALUES (10, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\nimport java.util.Arrays;\n\npublic class Solution {\n    \n    // 必须要有的主函数，用于接收沙箱喂进来的标准输入\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n        \n        // 1. 读取第一行：数组元素 (例如 \"2 7 11 15\")\n        String[] numsStr = scanner.nextLine().trim().split(\" \");\n        int[] nums = new int[numsStr.length];\n        for (int i = 0; i < numsStr.length; i++) {\n            nums[i] = Integer.parseInt(numsStr[i]);\n        }\n        \n        // 2. 读取第二行：目标值 (例如 9)\n        int target = scanner.nextInt();\n        \n        // 3. 调用你完美的核心算法\n        Solution sol = new Solution();\n        int[] result = sol.twoSum(nums, target);\n        \n        // 4. 将结果转为字符串打印到控制台，供沙箱抓取并与 Expected Output 对比\n        // Arrays.toString(result) 会打印出 \"[0, 1]\"，恰好与我们数据库里的格式完美匹配！\n        System.out.println(Arrays.toString(result));\n    }\n\n    // 你原来的核心算法代码，一字未改\n    public int[] twoSum(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 5, 1351, 0.00, '2026-03-29 06:13:01', '2026-03-29 06:13:01', 0);
