INSERT INTO `problem_submission` VALUES (13, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\nimport java.util.Arrays;\n\npublic class Solution {\n    \n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n        \n        // 1. 读取第一行，比如 \"[2,7,11,15]\" 或 \"[2, 7, 11, 15]\"\n        String line = scanner.nextLine().trim();\n        \n        // 去除开头的 \"[\" 和结尾的 \"]\"\n        line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n        \n        // 按逗号分割字符串\n        String[] numsStr = line.split(\",\");\n        int[] nums = new int[numsStr.length];\n        for (int i = 0; i < numsStr.length; i++) {\n            // trim() 去除数字两边可能存在的空格，然后强转\n            nums[i] = Integer.parseInt(numsStr[i].trim());\n        }\n        \n        // 2. 读取第二行目标值\n        int target = scanner.nextInt();\n        \n        // 3. 调用核心算法\n        Solution sol = new Solution();\n        int[] result = sol.twoSum(nums, target);\n        \n        // 4. 打印结果\n        // Arrays.toString 会输出 \"[0, 1]\"。如果数据库 Expected Output 没有空格(比如 \"[0,1]\")，\n        // 可以加上 .replace(\" \", \"\") 确保严丝合缝匹配。\n        System.out.println(Arrays.toString(result));\n    }\n\n    // 你完美的核心算法代码，一字未改\n    public int[] twoSum(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 2, 1239, 0.00, '2026-03-29 06:19:24', '2026-03-29 06:19:24', 0);
INSERT INTO `problem_submission` VALUES (14, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\nimport java.util.Arrays;\n\npublic class Solution {\n    \n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n        \n        // 1. 读取第一行，比如 \"[2,7,11,15]\" 或 \"[2, 7, 11, 15]\"\n        String line = scanner.nextLine().trim();\n        \n        // 去除开头的 \"[\" 和结尾的 \"]\"\n        line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n        \n        // 按逗号分割字符串\n        String[] numsStr = line.split(\",\");\n        int[] nums = new int[numsStr.length];\n        for (int i = 0; i < numsStr.length; i++) {\n            // trim() 去除数字两边可能存在的空格，然后强转\n            nums[i] = Integer.parseInt(numsStr[i].trim());\n        }\n        \n        // 2. 读取第二行目标值\n        int target = scanner.nextInt();\n        \n        // 3. 调用核心算法\n        Solution sol = new Solution();\n        int[] result = sol.twoSum(nums, target);\n        \n        // 4. 将结果转为字符串打印到控制台\n        // 去除 Arrays.toString 默认产生的空格，确保输出严格为 \"[0,1]\" 格式\n        System.out.println(Arrays.toString(result).replace(\" \", \"\"));\n    }\n\n    // 你完美的核心算法代码，一字未改\n    public int[] twoSum(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 1, 3132, 0.00, '2026-03-29 06:21:06', '2026-03-29 06:21:06', 0);
