INSERT INTO `problem_submission` VALUES (17, 3, 2, 'java', '// 在这里开始你的编码...\nimport java.util.Scanner;\n\npublic class Solution {\n\n    // 1. ACM 模式必带的程序入口\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        // 如果有输入数据\n        if (scanner.hasNextInt()) {\n            // 读取输入的整数 n\n            int n = scanner.nextInt();\n            \n            // 调用核心算法并直接打印结果\n            Solution sol = new Solution();\n            System.out.println(sol.climbStairs(n));\n        }\n        scanner.close();\n    }\n\n    // 2. 核心算法逻辑 (空间复杂度优化到 O(1) 的动态规划)\n    public int climbStairs(int n) {\n        if (n <= 2) {\n            return n;\n        }\n        // p 代表 f(x-2), q 代表 f(x-1), r 代表 f(x)\n        int p = 1, q = 2, r = 0;\n        for (int i = 3; i <= n; i++) {\n            r = p + q;\n            p = q;\n            q = r;\n        }\n        return r;\n    }\n}', 1, 4202, 0.00, '2026-03-29 06:41:44', '2026-03-29 06:41:44', 0);
