INSERT INTO `problem_submission` VALUES (103, 3, 20, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     * 采用回溯算法解决 N 皇后问题，并通过布尔数组实现 O(1) 复杂度的剪枝。\n     * * @param n 棋盘大小及皇后数量\n     * @return 所有合法的棋盘放置方案\n     */\n    public List<List<String>> solve(int n) {\n        List<List<String>> results = new ArrayList<>();\n        // 边界处理\n        if (n <= 0) return results;\n\n        // queens[i] 记录第 i 行放置的皇后的列索引\n        int[] queens = new int[n];\n        Arrays.fill(queens, -1);\n\n        // 冲突检测辅助数组 (空间换时间)\n        boolean[] columns = new boolean[n];\n        boolean[] diagonals1 = new boolean[2 * n - 1]; // 主对角线 (row - col + n - 1)\n        boolean[] diagonals2 = new boolean[2 * n - 1]; // 副对角线 (row + col)\n\n        backtrack(results, queens, n, 0, columns, diagonals1, diagonals2);\n        return results;\n    }\n\n    /**\n     * 深度优先搜索（DFS）回溯主体\n     */\n    private void backtrack(List<List<String>> results, int[] queens, int n, int row, \n                           boolean[] columns, boolean[] diagonals1, boolean[] diagonals2) {\n        // Base Case: 如果成功遍历到了第 n 行，说明所有皇后放置完毕\n        if (row == n) {\n            results.add(generateBoard(queens, n));\n            return;\n        }\n\n        // 遍历当前行的每一列，尝试放置皇后\n        for (int col = 0; col < n; col++) {\n            int diag1Index = row - col + n - 1;\n            int diag2Index = row + col;\n\n            // 剪枝: 如果当前列或两个对角线方向已经被占据，跳过\n            if (columns[col] || diagonals1[diag1Index] || diagonals2[diag2Index]) {\n                continue;\n            }\n\n            // 做选择 (Make Choice): 放置皇后，更新占用状态\n            queens[row] = col;\n            columns[col] = true;\n            diagonals1[diag1Index] = true;\n            diagonals2[diag2Index] = true;\n\n            // 递归进入下一行\n            backtrack(results, queens, n, row + 1, columns, diagonals1, diagonals2);\n\n            // 撤销选择 (Undo Choice/Backtrack): 恢复原始状态\n            queens[row] = -1;\n            columns[col] = false;\n            diagonals1[diag1Index] = false;\n            diagonals2[diag2Index] = false;\n        }\n    }\n\n    /**\n     * 根据皇后的列索引数组，生成符合题目要求的棋盘快照\n     */\n    private List<String> generateBoard(int[] queens, int n) {\n        List<String> board = new ArrayList<>();\n        for (int i = 0; i < n; i++) {\n            char[] row = new char[n];\n            Arrays.fill(row, \'.\');\n            row[queens[i]] = \'Q\';\n            board.add(new String(row));\n        }\n        return board;\n    }\n\n    /**\n     * 辅助方法：将结果严格格式化为带有双引号的 JSON 风格字符串\n     * 以匹配 Example 1 的输出：[[\".Q..\",\"...Q\",\"Q...\",\"..Q.\"], ...]\n     */\n    private static String formatResult(List<List<String>> results) {\n        StringBuilder sb = new StringBuilder();\n        sb.append(\"[\");\n        for (int i = 0; i < results.size(); i++) {\n            sb.append(\"[\");\n            List<String> board = results.get(i);\n            for (int j = 0; j < board.size(); j++) {\n                sb.append(\"\\\"\").append(board.get(j)).append(\"\\\"\");\n                if (j < board.size() - 1) {\n                    sb.append(\",\");\n                }\n            }\n            sb.append(\"]\");\n            if (i < results.size() - 1) {\n                sb.append(\",\");\n            }\n        }\n        sb.append(\"]\");\n        return sb.toString();\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        try {\n            if (scanner.hasNextInt()) {\n                // 1. 读取并解析输入数据\n                int n = scanner.nextInt();\n                \n                // 边界异常检测\n                if (n < 1) {\n                    System.out.println(\"[]\");\n                    return;\n                }\n\n                // 2. 实例化并调用核心算法\n                Solution sol = new Solution();\n                List<List<String>> result = sol.solve(n);\n                \n                // 3. 按照题目要求的格式打印输出\n                System.out.println(formatResult(result));\n            }\n        } catch (InputMismatchException e) {\n            // 严谨的错误处理，防止非法输入导致程序崩溃\n            System.err.println(\"Input format error: Please provide a valid integer.\");\n        } finally {\n            // 防止内存/句柄泄漏\n            scanner.close();\n        }\n    }\n}', 1, 2298, 0.00, '2026-04-03 10:56:06', '2026-04-03 10:56:06', 0);
