INSERT INTO `problem_submission` VALUES (105, 3, 19, 'java', 'import java.util.*;\nimport java.io.*;\nimport java.util.regex.*;\n\n/**\n * 链表节点定义 (ACM模式必备基础结构)\n */\nclass ListNode {\n    int val;\n    ListNode next;\n    ListNode() {}\n    ListNode(int val) { this.val = val; }\n    ListNode(int val, ListNode next) { this.val = val; this.next = next; }\n}\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑：利用小顶堆进行 K 路归并\n     * @param lists 升序链表数组\n     * @return 合并后的单链表头节点\n     */\n    public ListNode solve(ListNode[] lists) {\n        // 边界情况防御\n        if (lists == null || lists.length == 0) {\n            return null;\n        }\n\n        // 构造小顶堆 (Min-Heap)，按照节点的 val 属性升序排列\n        PriorityQueue<ListNode> minHeap = new PriorityQueue<>(\n            lists.length, \n            (a, b) -> Integer.compare(a.val, b.val)\n        );\n\n        // 初始化：将所有非空链表的头节点加入堆中\n        for (ListNode head : lists) {\n            if (head != null) {\n                minHeap.offer(head);\n            }\n        }\n\n        // 使用 Dummy Node 简化头节点的边界处理\n        ListNode dummy = new ListNode(-1);\n        ListNode current = dummy;\n\n        // 持续从堆顶弹出当前全局最小节点，并推入其后继节点\n        while (!minHeap.isEmpty()) {\n            // 1. 获取最小节点并链接\n            ListNode minNode = minHeap.poll();\n            current.next = minNode;\n            current = current.next;\n\n            // 2. 如果该链表还有下一个节点，将其推入堆中参与下一轮竞选\n            if (minNode.next != null) {\n                minHeap.offer(minNode.next);\n            }\n        }\n\n        // 斩断尾部（防御性编程，尽管在此题中原链表尾部已经是 null）\n        current.next = null;\n        \n        return dummy.next;\n    }\n\n    /**\n     * 辅助方法：将 ListNode 序列化为要求的数组字符串格式\n     */\n    private static String formatResult(ListNode head) {\n        if (head == null) return \"[]\";\n        StringBuilder sb = new StringBuilder();\n        sb.append(\"[\");\n        while (head != null) {\n            sb.append(head.val);\n            if (head.next != null) {\n                sb.append(\",\");\n            }\n            head = head.next;\n        }\n        sb.append(\"]\");\n        return sb.toString();\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 解析嵌套数组字符串，生成 ListNode[]，并打印结果\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        try {\n            if (scanner.hasNextLine()) {\n                // 1. 读取并清理输入数据\n                String line = scanner.nextLine().trim();\n                \n                // 处理极端的全空情况\n                if (line.equals(\"[]\") || line.isEmpty()) {\n                    System.out.println(\"[]\");\n                    return;\n                }\n\n                // 2. 正则解析输入数据 [[1,4,5],[1,3,4],[2,6]]\n                // 匹配中括号内的内容，且内容不包含其他中括号\n                Matcher m = Pattern.compile(\"\\\\[([^\\\\[\\\\]]*)\\\\]\").matcher(line);\n                List<ListNode> listBuilder = new ArrayList<>();\n                \n                while (m.find()) {\n                    String content = m.group(1).trim();\n                    if (content.isEmpty()) {\n                        listBuilder.add(null);\n                        continue;\n                    }\n                    \n                    String[] nums = content.split(\",\");\n                    ListNode dummy = new ListNode(0);\n                    ListNode curr = dummy;\n                    for (String num : nums) {\n                        curr.next = new ListNode(Integer.parseInt(num.trim()));\n                        curr = curr.next;\n                    }\n                    listBuilder.add(dummy.next);\n                }\n                \n                ListNode[] lists = listBuilder.toArray(new ListNode[0]);\n                \n                // 3. 实例化并调用核心算法\n                Solution sol = new Solution();\n                ListNode resultNode = sol.solve(lists);\n                \n                // 4. 按照题目要求的格式打印输出\n                System.out.println(formatResult(resultNode));\n            }\n        } catch (Exception e) {\n            // 严谨的错误处理，防止非法序列化输入导致程序崩溃\n            System.err.println(\"Input parsing error: \" + e.getMessage());\n        } finally {\n            // 防止内存/句柄泄漏\n            scanner.close();\n        }\n    }\n}', 1, 3692, 0.00, '2026-04-03 11:00:38', '2026-04-03 11:00:38', 0);
