INSERT INTO `problem_submission` VALUES (107, 3, 18, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑：接雨水 (Trapping Rain Water)\n     * 采用最优的【双指针法 (Two Pointers)】，时间复杂度 O(N)，空间复杂度 O(1)。\n     * * @param height 柱子的高度数组\n     * @return 能够接住的雨水总量\n     */\n    public int solve(int[] height) {\n        // 边界情况防御：少于3根柱子无法形成凹槽接水\n        if (height == null || height.length <= 2) {\n            return 0;\n        }\n\n        int left = 0;\n        int right = height.length - 1;\n        int leftMax = 0;\n        int rightMax = 0;\n        int totalWater = 0;\n\n        // 双指针向中间逼近\n        while (left < right) {\n            // 动态维护左右两边的最高柱子\n            leftMax = Math.max(leftMax, height[left]);\n            rightMax = Math.max(rightMax, height[right]);\n\n            // 根据木桶原理，较短的一边决定了当前位置能接的水量\n            if (height[left] < height[right]) {\n                // 左侧存在更高的柱子作为屏障，右侧有 rightMax 兜底，可以安全结算左侧\n                totalWater += leftMax - height[left];\n                left++;\n            } else {\n                // 右侧存在更高的柱子作为屏障，左侧有 leftMax 兜底，可以安全结算右侧\n                totalWater += rightMax - height[right];\n                right--;\n            }\n        }\n\n        return totalWater;\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 解析标准输入 (如: [0,1,0,2,1,0,1,3,2,1,2,1]) 并打印结果\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        try {\n            if (scanner.hasNextLine()) {\n                String line = scanner.nextLine().trim();\n                \n                // 处理空输入的情况\n                if (line.isEmpty() || line.equals(\"[]\")) {\n                    System.out.println(0);\n                    return;\n                }\n\n                // 清洗输入数据，去除首尾中括号\n                line = line.replaceAll(\"\\\\[|\\\\]\", \"\");\n                if (line.isEmpty()) {\n                    System.out.println(0);\n                    return;\n                }\n\n                // 按逗号分割并转换为整型数组\n                String[] parts = line.split(\",\");\n                int[] height = new int[parts.length];\n                for (int i = 0; i < parts.length; i++) {\n                    height[i] = Integer.parseInt(parts[i].trim());\n                }\n\n                // 实例化并调用核心算法\n                Solution sol = new Solution();\n                int result = sol.solve(height);\n                \n                // 打印输出结果\n                System.out.println(result);\n            }\n        } catch (NumberFormatException e) {\n            // 防止非法格式输入导致程序崩溃\n            System.err.println(\"Input parsing error: Array elements must be integers.\");\n        } catch (Exception e) {\n            System.err.println(\"An unexpected error occurred: \" + e.getMessage());\n        } finally {\n            // 防止内存/句柄泄漏\n            scanner.close();\n        }\n    }\n}\n', 1, 2197, 0.00, '2026-04-03 11:03:42', '2026-04-03 11:03:42', 0);
INSERT INTO `problem_submission` VALUES (108, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\nimport java.util.Arrays;\n\npublic class Solution {\n    \n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n        \n        // 1. 读取第一行，比如 \"[2,7,11,15]\" 或 \"[2, 7, 11, 15]\"\n        String line = scanner.nextLine().trim();\n        \n        // 去除开头的 \"[\" 和结尾的 \"]\"\n        line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n        \n        // 按逗号分割字符串\n        String[] numsStr = line.split(\",\");\n        int[] nums = new int[numsStr.length];\n        for (int i = 0; i < numsStr.length; i++) {\n            // trim() 去除数字两边可能存在的空格，然后强转\n            nums[i] = Integer.parseInt(numsStr[i].trim());\n        }\n        \n        // 2. 读取第二行目标值\n        int target = scanner.nextInt();\n        \n        // 3. 调用核心算法\n        Solution sol = new Solution();\n        int[] result = sol.twoSum(nums, target);\n        \n        // 4. 将结果转为字符串打印到控制台\n        // 去除 Arrays.toString 默认产生的空格，确保输出严格为 \"[0,1]\" 格式\n        System.out.println(Arrays.toString(result).replace(\" \", \"\"));\n    }\n\n    // 你完美的核心算法代码，一字未改\n    public int[] twoSum(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 1, 3349, 0.00, '2026-04-03 11:14:15', '2026-04-03 11:14:15', 0);
INSERT INTO `problem_submission` VALUES (109, 3, 1, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\nimport java.util.Arrays;\n\npublic class Solution {\n    \n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n        \n        // 1. 读取第一行，比如 \"[2,7,11,15]\" 或 \"[2, 7, 11, 15]\"\n        String line = scanner.nextLine().trim();\n        \n        // 去除开头的 \"[\" 和结尾的 \"]\"\n        line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n        \n        // 按逗号分割字符串\n        String[] numsStr = line.split(\",\");\n        int[] nums = new int[numsStr.length];\n        for (int i = 0; i < numsStr.length; i++) {\n            // trim() 去除数字两边可能存在的空格，然后强转\n            nums[i] = Integer.parseInt(numsStr[i].trim());\n        }\n        \n        // 2. 读取第二行目标值\n        int target = scanner.nextInt();\n        \n        // 3. 调用核心算法\n        Solution sol = new Solution();\n        int[] result = sol.twoSum(nums, target);\n        \n        // 4. 将结果转为字符串打印到控制台\n        // 去除 Arrays.toString 默认产生的空格，确保输出严格为 \"[0,1]\" 格式\n        System.out.println(Arrays.toString(result).replace(\" \", \"\"));\n    }\n\n    // 你完美的核心算法代码，一字未改\n    public int[] twoSum(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        throw new IllegalArgumentException(\"No two sum solution\");\n    }\n}', 1, 3614, 0.00, '2026-04-03 11:16:29', '2026-04-03 11:16:29', 0);
