INSERT INTO `problem_submission` VALUES (114, 3, 8, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑：字符串相加\n     * 采用双指针模拟人工加法（竖式相加），从低位（字符串末尾）向高位逐位相加。\n     * 时间复杂度 O(max(L1, L2))，空间复杂度 O(max(L1, L2))。\n     * * @param num1 第一个非负整数字符串\n     * @param num2 第二个非负整数字符串\n     * @return 相加后的结果字符串\n     */\n    public String solve(String num1, String num2) {\n        // 健壮性检查\n        if (num1 == null || num1.isEmpty()) return num2;\n        if (num2 == null || num2.isEmpty()) return num1;\n\n        StringBuilder result = new StringBuilder();\n        int i = num1.length() - 1;\n        int j = num2.length() - 1;\n        int carry = 0; // 进位状态记录\n\n        // 当任意一个字符串还有剩余字符，或者还有进位时，继续计算\n        while (i >= 0 || j >= 0 || carry != 0) {\n            // 获取当前位的值，如果指针越界（已遍历完）则补 0\n            int x = i >= 0 ? num1.charAt(i) - \'0\' : 0;\n            int y = j >= 0 ? num2.charAt(j) - \'0\' : 0;\n\n            int sum = x + y + carry;\n            result.append(sum % 10); // 记录当前位的计算结果\n            carry = sum / 10;        // 计算进位，供下一轮使用\n\n            i--;\n            j--;\n        }\n\n        // 因为是从低位向高位 append 的，最后需要反转字符串\n        return result.reverse().toString();\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 解析标准输入并打印结果\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        try {\n            if (scanner.hasNextLine()) {\n                String line = scanner.nextLine().trim();\n                if (line.isEmpty()) return;\n\n                // 预处理：兼容纯空格分隔 \"11 123\" 和题目示例格式 \"num1 = \\\"11\\\", num2 = \\\"123\\\"\"\n                line = line.replaceAll(\"num[12]\\\\s*=\\\\s*\", \"\"); // 移除变量声明声明\n                line = line.replaceAll(\"\\\"\", \"\");               // 移除双引号\n                \n                // 按逗号或一个/多个空格分割\n                String[] parts = line.split(\"[,\\\\s]+\");\n                \n                if (parts.length >= 2) {\n                    String num1 = parts[0].trim();\n                    String num2 = parts[1].trim();\n\n                    // 实例化并调用核心算法\n                    Solution sol = new Solution();\n                    String sum = sol.solve(num1, num2);\n                    \n                    // 按照题目要求格式打印输出（结果为字符串形式）\n                    System.out.println(\"\\\"\" + sum + \"\\\"\");\n                }\n            }\n        } catch (Exception e) {\n            // 严谨的错误处理，防止异常导致进程崩溃\n            System.err.println(\"Input parsing error: \" + e.getMessage());\n        } finally {\n            // 防止系统资源泄漏\n            scanner.close();\n        }\n    }\n}', 2, 1111, 0.00, '2026-04-03 11:36:36', '2026-04-03 11:36:36', 0);
INSERT INTO `problem_submission` VALUES (115, 3, 8, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑：字符串相加 (逻辑不变，绝对正确)\n     */\n    public String solve(String num1, String num2) {\n        if (num1 == null || num1.isEmpty()) return num2;\n        if (num2 == null || num2.isEmpty()) return num1;\n\n        StringBuilder result = new StringBuilder();\n        int i = num1.length() - 1;\n        int j = num2.length() - 1;\n        int carry = 0;\n\n        while (i >= 0 || j >= 0 || carry != 0) {\n            int x = i >= 0 ? num1.charAt(i) - \'0\' : 0;\n            int y = j >= 0 ? num2.charAt(j) - \'0\' : 0;\n\n            int sum = x + y + carry;\n            result.append(sum % 10);\n            carry = sum / 10;\n\n            i--;\n            j--;\n        }\n\n        return result.reverse().toString();\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口 (已重构防御性 I/O)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        Solution sol = new Solution();\n        \n        try {\n            // 修复 1: 使用 while 持续监听，处理 OJ 灌入的所有测试用例\n            while (scanner.hasNext()) {\n                // 修复 2: 使用 next() 获取 token，无视空格和换行符带来的影响\n                String s1 = scanner.next();\n                String s2 = scanner.next();\n\n                // 修复 3: 正则清洗，剔除一切非数字字符\n                // 完美兼容纯净输入 \"11\" 和脏输入 \"num1=\\\"11\\\",\"\n                String num1 = s1.replaceAll(\"[^0-9]\", \"\");\n                String num2 = s2.replaceAll(\"[^0-9]\", \"\");\n                \n                // 防御空字符串情况 (比如被完全清洗掉了)\n                if (num1.isEmpty()) num1 = \"0\";\n                if (num2.isEmpty()) num2 = \"0\";\n\n                String sum = sol.solve(num1, num2);\n                \n                // 修复 4: 抛弃冗余的双引号，输出最纯净的答案\n                System.out.println(sum);\n            }\n        } catch (Exception e) {\n            System.err.println(\"Execution Error: \" + e.getMessage());\n        } finally {\n            scanner.close();\n        }\n    }\n}', 2, 1215, 0.00, '2026-04-03 11:38:18', '2026-04-03 11:38:18', 0);
INSERT INTO `problem_submission` VALUES (116, 3, 8, 'java', 'import java.util.Scanner;\n\npublic class Solution { \n\n    /**\n     * 核心算法：双指针竖式相加\n     */\n    public String solve(String num1, String num2) {\n        StringBuilder result = new StringBuilder();\n        int i = num1.length() - 1;\n        int j = num2.length() - 1;\n        int carry = 0;\n\n        while (i >= 0 || j >= 0 || carry != 0) {\n            int x = i >= 0 ? num1.charAt(i) - \'0\' : 0;\n            int y = j >= 0 ? num2.charAt(j) - \'0\' : 0;\n\n            int sum = x + y + carry;\n            result.append(sum % 10);\n            carry = sum / 10;\n\n            i--;\n            j--;\n        }\n\n        return result.reverse().toString();\n    }\n\n    /**\n     * 极简且最稳健的 I/O 入口\n     */\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n        Solution sol = new Solution(); // 实例化对应修改为 Solution\n        \n        // 持续读取所有测试用例，直到输入流结束\n        while (sc.hasNext()) {\n            // next() 会自动跳过多余的空格和换行，精准抓取下一个连续字符串\n            String num1 = sc.next();\n            String num2 = sc.next();\n            \n            // 直接计算并输出最纯净的结果\n            System.out.println(sol.solve(num1, num2));\n        }\n        \n        sc.close();\n    }\n}', 2, 1094, 0.00, '2026-04-03 11:42:10', '2026-04-03 11:42:10', 0);
INSERT INTO `problem_submission` VALUES (117, 3, 8, 'java', 'import java.util.Scanner;\n\npublic class Solution { \n\n    /**\n     * 核心算法：双指针竖式相加 (逻辑绝对正确，无需修改)\n     */\n    public String solve(String num1, String num2) {\n        // 防止空字符串导致越界\n        if (num1.isEmpty()) num1 = \"0\";\n        if (num2.isEmpty()) num2 = \"0\";\n\n        StringBuilder result = new StringBuilder();\n        int i = num1.length() - 1;\n        int j = num2.length() - 1;\n        int carry = 0;\n\n        while (i >= 0 || j >= 0 || carry != 0) {\n            int x = i >= 0 ? num1.charAt(i) - \'0\' : 0;\n            int y = j >= 0 ? num2.charAt(j) - \'0\' : 0;\n\n            int sum = x + y + carry;\n            result.append(sum % 10);\n            carry = sum / 10;\n\n            i--;\n            j--;\n        }\n\n        return result.reverse().toString();\n    }\n\n    /**\n     * I/O 入口 (增加双引号清洗逻辑)\n     */\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n        Solution sol = new Solution(); \n        \n        while (sc.hasNext()) {\n            // 核心修复：读取原始字符串后，立刻用正则剔除所有的双引号 (\") 和逗号 (,)\n            // 这样无论输入是 \"11\" 还是 11, 都会被清洗为纯净的 11\n            String num1 = sc.next().replaceAll(\"[\\\"\',]\", \"\");\n            String num2 = sc.next().replaceAll(\"[\\\"\',]\", \"\");\n            \n            System.out.println(sol.solve(num1, num2));\n        }\n        \n        sc.close();\n    }\n}', 2, 1088, 0.00, '2026-04-03 11:43:35', '2026-04-03 11:43:35', 0);
INSERT INTO `problem_submission` VALUES (118, 3, 8, 'java', 'import java.util.Scanner;\n\npublic class Solution { \n\n    /**\n     * 核心算法：双指针模拟竖式相加 (时间 O(max(L1,L2)), 空间 O(max(L1,L2)))\n     */\n    public String solve(String num1, String num2) {\n        // 防御性编程：防止空输入引发空指针或越界\n        if (num1.isEmpty()) num1 = \"0\";\n        if (num2.isEmpty()) num2 = \"0\";\n\n        StringBuilder result = new StringBuilder();\n        int i = num1.length() - 1;\n        int j = num2.length() - 1;\n        int carry = 0; // 进位状态寄存器\n\n        while (i >= 0 || j >= 0 || carry != 0) {\n            int x = i >= 0 ? num1.charAt(i) - \'0\' : 0;\n            int y = j >= 0 ? num2.charAt(j) - \'0\' : 0;\n\n            int sum = x + y + carry;\n            result.append(sum % 10);\n            carry = sum / 10;\n\n            i--;\n            j--;\n        }\n\n        return result.reverse().toString();\n    }\n\n    /**\n     * 工业级 I/O 入口\n     */\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n        Solution sol = new Solution(); \n        \n        while (sc.hasNext()) {\n            // 1. 数据清洗：抹除输入数据中自带的所有双引号和逗号，提取纯净数字\n            String num1 = sc.next().replaceAll(\"[\\\"\',]\", \"\");\n            String num2 = sc.next().replaceAll(\"[\\\"\',]\", \"\");\n            \n            // 2. 核心计算\n            String result = sol.solve(num1, num2);\n            \n            // 3. 序列化对齐：强制在输出结果前后拼接双引号，满足评测机的无脑文本比对\n            System.out.println(\"\\\"\" + result + \"\\\"\");\n        }\n        \n        sc.close();\n    }\n}', 1, 4739, 0.00, '2026-04-03 11:45:32', '2026-04-03 11:45:32', 0);
INSERT INTO `problem_submission` VALUES (119, 2, 1, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public int[] solve(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        return new int[0];\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 假设输入格式示例：\n        // [2,7,11,15]\n        // 9\n        if (scanner.hasNextLine()) {\n            // 1. 读取并解析输入数据\n            String line = scanner.nextLine().trim();\n            // 去除前后方括号\n            line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n            String[] parts = line.split(\",\");\n            int[] nums = new int[parts.length];\n            for (int i = 0; i < parts.length; i++) {\n                nums[i] = Integer.parseInt(parts[i].trim());\n            }\n            \n            int target = Integer.parseInt(scanner.nextLine().trim());\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            int[] result = sol.solve(nums, target);\n            \n            // 3. 按照题目要求的格式打印输出\n            if (result.length == 2) {\n                System.out.println(\"[\" + result[0] + \",\" + result[1] + \"]\");\n            } else {\n                System.out.println(\"[]\");\n            }\n        }\n        scanner.close();\n    }\n}', 1, 2978, 0.00, '2026-04-04 02:15:04', '2026-04-04 02:15:04', 0);
