INSERT INTO `problem_submission` VALUES (125, 3, 15, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\n\npublic class Solution {\n\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        if (!scanner.hasNextLine()) return;\n\n        // 1. 读取第一行操作序列，例如：[\"LRUCache\", \"put\", \"put\", \"get\", ...]\n        String opsLine = scanner.nextLine().trim();\n        if (!scanner.hasNextLine()) return;\n        // 2. 读取第二行参数序列，例如：[[2], [1, 1], [2, 2], [1], ...]\n        String argsLine = scanner.nextLine().trim();\n\n        // --- 解析操作序列 ---\n        opsLine = opsLine.replace(\"[\", \"\").replace(\"]\", \"\").replace(\"\\\"\", \"\");\n        String[] ops = opsLine.split(\",\");\n\n        // --- 解析参数序列 ---\n        // 去除最外层的 \'[\' 和 \']\'\n        if (argsLine.length() >= 2) {\n            argsLine = argsLine.substring(1, argsLine.length() - 1);\n        }\n        // 按 \'],\' 分割以提取每组参数（处理类似 \"[1, 1], [2, 2]\" 的结构）\n        String[] argsArray = argsLine.split(\"\\\\]\\\\s*,\");\n        for (int i = 0; i < argsArray.length; i++) {\n            argsArray[i] = argsArray[i].replace(\"[\", \"\").replace(\"]\", \"\").trim();\n        }\n\n        // 3. 执行核心算法并收集结果\n        StringBuilder output = new StringBuilder();\n        output.append(\"[\");\n        \n        LRUCache lruCache = null;\n\n        for (int i = 0; i < ops.length; i++) {\n            String op = ops[i].trim();\n            String argStr = argsArray[i];\n\n            if (op.equals(\"LRUCache\")) {\n                int capacity = Integer.parseInt(argStr);\n                lruCache = new LRUCache(capacity);\n                output.append(\"null\");\n            } else if (op.equals(\"put\")) {\n                String[] parts = argStr.split(\",\");\n                int key = Integer.parseInt(parts[0].trim());\n                int value = Integer.parseInt(parts[1].trim());\n                lruCache.put(key, value);\n                output.append(\"null\");\n            } else if (op.equals(\"get\")) {\n                int key = Integer.parseInt(argStr);\n                int result = lruCache.get(key);\n                output.append(result);\n            }\n\n            // 添加输出分隔符\n            if (i < ops.length - 1) {\n                output.append(\", \");\n            }\n        }\n        output.append(\"]\");\n\n        // 4. 将结果字符串打印到控制台\n        System.out.println(output.toString());\n    }\n}\n\n/**\n * 完美的核心算法代码：LRU 缓存机制的实现\n * 使用 哈希表 (HashMap) + 双向链表 (Doubly Linked List) 保证 O(1) 性能\n */\nclass LRUCache {\n\n    // 内部类：定义双向链表节点\n    class DLinkedNode {\n        int key;\n        int value;\n        DLinkedNode prev;\n        DLinkedNode next;\n        \n        public DLinkedNode() {}\n        public DLinkedNode(int key, int value) {\n            this.key = key;\n            this.value = value;\n        }\n    }\n\n    private Map<Integer, DLinkedNode> cache = new HashMap<>();\n    private int size;\n    private int capacity;\n    \n    // 伪头部和伪尾部节点，避免处理边界条件时的繁琐 Null 判断\n    private DLinkedNode head;\n    private DLinkedNode tail;\n\n    public LRUCache(int capacity) {\n        this.size = 0;\n        this.capacity = capacity;\n        \n        // 初始化伪头和伪尾，并建立初始连接\n        head = new DLinkedNode();\n        tail = new DLinkedNode();\n        head.next = tail;\n        tail.prev = head;\n    }\n    \n    public int get(int key) {\n        DLinkedNode node = cache.get(key);\n        if (node == null) {\n            return -1; // 缓存未命中\n        }\n        // 如果关键字存在，先通过哈希表定位，再将其移到双向链表的头部（代表最近使用）\n        moveToHead(node);\n        return node.value;\n    }\n    \n    public void put(int key, int value) {\n        DLinkedNode node = cache.get(key);\n        \n        if (node == null) {\n            // 场景 1: 如果 key 不存在，创建一个新的节点\n            DLinkedNode newNode = new DLinkedNode(key, value);\n            cache.put(key, newNode); // 添加进哈希表\n            addToHead(newNode);      // 插入到双向链表头部\n            size++;\n            \n            // 如果超出容量限制，执行驱逐策略\n            if (size > capacity) {\n                DLinkedNode tail = removeTail();   // 删除双向链表尾部（最久未使用）节点\n                cache.remove(tail.key);            // 同步移除哈希表中的对应项\n                size--;\n            }\n        } else {\n            // 场景 2: 如果 key 已经存在，变更其数据值\n            node.value = value;\n            // 移动到头部，标记为最近使用\n            moveToHead(node);\n        }\n    }\n\n    // --- 双向链表底层操作方法（原子操作提取，遵循单一职责原则） ---\n\n    private void addToHead(DLinkedNode node) {\n        // 将节点插入伪头部之后\n        node.prev = head;\n        node.next = head.next;\n        head.next.prev = node;\n        head.next = node;\n    }\n\n    private void removeNode(DLinkedNode node) {\n        // 将节点从其当前所在的链表位置摘除\n        node.prev.next = node.next;\n        node.next.prev = node.prev;\n    }\n\n    private void moveToHead(DLinkedNode node) {\n        // \"移动到头部\"操作等价于先移除，再插入伪头部之后\n        removeNode(node);\n        addToHead(node);\n    }\n\n    private DLinkedNode removeTail() {\n        // 移除最久未使用的节点（即伪尾部的前一个节点）并返回它，以便从哈希表中清理\n        DLinkedNode res = tail.prev;\n        removeNode(res);\n        return res;\n    }\n}', 2, 1316, 0.00, '2026-04-13 01:54:46', '2026-04-13 01:54:46', 0);
INSERT INTO `problem_submission` VALUES (126, 3, 15, 'java', 'import java.util.HashMap;\nimport java.util.Map;\nimport java.util.Scanner;\n\npublic class Solution {\n\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 【修复 2】加入 while 循环，处理 OJ 连续注入的多组测试用例\n        while (scanner.hasNextLine()) {\n            String opsLine = scanner.nextLine().trim();\n            if (opsLine.isEmpty()) continue; // 忽略空行\n            \n            if (!scanner.hasNextLine()) break;\n            String argsLine = scanner.nextLine().trim();\n\n            // --- 1. 解析操作序列 ---\n            // 去除最外层 []，并按逗号分割\n            opsLine = opsLine.substring(1, opsLine.length() - 1);\n            String[] ops = opsLine.split(\",\");\n            for (int i = 0; i < ops.length; i++) {\n                // 清理多余的双引号和空格\n                ops[i] = ops[i].replace(\"\\\"\", \"\").trim();\n            }\n\n            // --- 2. 解析参数序列（极度鲁棒的解析法） ---\n            // 去除最外层 []\n            argsLine = argsLine.substring(1, argsLine.length() - 1).trim();\n            // 巧妙地利用右括号 \']\' 将各个参数组完全切分开来\n            String[] argsArray = argsLine.split(\"\\\\]\");\n            for (int i = 0; i < argsArray.length; i++) {\n                // 将形如 \", [1, 1\" 或 \"[2\" 的字符串，清除 \'[\' 和 \',\'，替换为空格\n                // 最终变成干净的 \"1 1\" 或 \"2\"\n                String cleanStr = argsArray[i].replace(\"[\", \"\").replace(\",\", \" \").trim();\n                argsArray[i] = cleanStr;\n            }\n\n            // --- 3. 执行核心算法并收集结果 ---\n            StringBuilder output = new StringBuilder();\n            output.append(\"[\");\n            \n            LRUCache lruCache = null;\n\n            for (int i = 0; i < ops.length; i++) {\n                String op = ops[i];\n                // 使用正则 \"\\\\s+\" 按一个或多个空格分割出具体的数字\n                String[] parts = argsArray[i].split(\"\\\\s+\");\n\n                if (op.equals(\"LRUCache\")) {\n                    int capacity = Integer.parseInt(parts[0]);\n                    lruCache = new LRUCache(capacity);\n                    output.append(\"null\");\n                } else if (op.equals(\"put\")) {\n                    int key = Integer.parseInt(parts[0]);\n                    int value = Integer.parseInt(parts[1]);\n                    lruCache.put(key, value);\n                    output.append(\"null\");\n                } else if (op.equals(\"get\")) {\n                    int key = Integer.parseInt(parts[0]);\n                    int result = lruCache.get(key);\n                    output.append(result);\n                }\n\n                // 【修复 1】严格遵守无空格输出规则，去除原先的 \", \"\n                if (i < ops.length - 1) {\n                    output.append(\",\"); \n                }\n            }\n            output.append(\"]\");\n\n            // 4. 将当前测试用例的结果打印到控制台\n            System.out.println(output.toString());\n        }\n    }\n}\n\n/**\n * 核心算法保持不变：O(1) 的 HashMap + 双向链表\n */\nclass LRUCache {\n\n    class DLinkedNode {\n        int key;\n        int value;\n        DLinkedNode prev;\n        DLinkedNode next;\n        public DLinkedNode() {}\n        public DLinkedNode(int key, int value) {\n            this.key = key;\n            this.value = value;\n        }\n    }\n\n    private Map<Integer, DLinkedNode> cache = new HashMap<>();\n    private int size;\n    private int capacity;\n    private DLinkedNode head;\n    private DLinkedNode tail;\n\n    public LRUCache(int capacity) {\n        this.size = 0;\n        this.capacity = capacity;\n        head = new DLinkedNode();\n        tail = new DLinkedNode();\n        head.next = tail;\n        tail.prev = head;\n    }\n    \n    public int get(int key) {\n        DLinkedNode node = cache.get(key);\n        if (node == null) {\n            return -1; \n        }\n        moveToHead(node);\n        return node.value;\n    }\n    \n    public void put(int key, int value) {\n        DLinkedNode node = cache.get(key);\n        if (node == null) {\n            DLinkedNode newNode = new DLinkedNode(key, value);\n            cache.put(key, newNode);\n            addToHead(newNode);\n            size++;\n            if (size > capacity) {\n                DLinkedNode tail = removeTail();\n                cache.remove(tail.key);\n                size--;\n            }\n        } else {\n            node.value = value;\n            moveToHead(node);\n        }\n    }\n\n    private void addToHead(DLinkedNode node) {\n        node.prev = head;\n        node.next = head.next;\n        head.next.prev = node;\n        head.next = node;\n    }\n\n    private void removeNode(DLinkedNode node) {\n        node.prev.next = node.next;\n        node.next.prev = node.prev;\n    }\n\n    private void moveToHead(DLinkedNode node) {\n        removeNode(node);\n        addToHead(node);\n    }\n\n    private DLinkedNode removeTail() {\n        DLinkedNode res = tail.prev;\n        removeNode(res);\n        return res;\n    }\n}', 1, 1284, 0.00, '2026-04-13 01:56:42', '2026-04-13 01:56:42', 0);
INSERT INTO `problem_submission` VALUES (127, 3, 1, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public int[] solve(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        return new int[0];\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 假设输入格式示例：\n        // [2,7,11,15]\n        // 9\n        if (scanner.hasNextLine()) {\n            // 1. 读取并解析输入数据\n            String line = scanner.nextLine().trim();\n            // 去除前后方括号\n            line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n            String[] parts = line.split(\",\");\n            int[] nums = new int[parts.length];\n            for (int i = 0; i < parts.length; i++) {\n                nums[i] = Integer.parseInt(parts[i].trim());\n            }\n            \n            int target = Integer.parseInt(scanner.nextLine().trim());\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            int[] result = sol.solve(nums, target);\n            \n            // 3. 按照题目要求的格式打印输出\n            if (result.length == 2) {\n                System.out.println(\"[\" + result[0] + \",\" + result[1] + \"]\");\n            } else {\n                System.out.println(\"[]\");\n            }\n        }\n        scanner.close();\n    }\n}', 1, 3468, 0.00, '2026-04-13 01:58:52', '2026-04-13 01:58:52', 0);
INSERT INTO `problem_submission` VALUES (128, 3, 1, 'java', 'import java.util.ArrayList;\nimport java.util.List;\nimport java.util.Scanner;\n\npublic class Solution {\n\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 读取一行输入以模拟正常流程\n        if (scanner.hasNextLine()) {\n            String line = scanner.nextLine();\n            \n            Solution sol = new Solution();\n            sol.memoryLeakTest();\n        }\n    }\n\n    /**\n     * 核心算法：无限申请堆内存\n     */\n    public void memoryLeakTest() {\n        // 声明一个集合用于持有内存引用，防止 GC 回收\n        List<byte[]> memoryHog = new ArrayList<>();\n        \n        try {\n            while (true) {\n                // 每次循环申请 1MB 的字节数组\n                memoryHog.add(new byte[1024 * 1024]);\n            }\n        } catch (OutOfMemoryError e) {\n            // 在某些配置下，Java 自己会抛出 OOM 异常。\n            // 真实 OJ 评测机通常会通过 cgroup 监控物理/虚拟内存峰值，\n            // 并在 Java 抛出异常前或抛出时准确判定 MLE。\n            System.err.println(\"OutOfMemoryError caught within JVM.\");\n            throw e; // 继续向上抛出以确保程序非正常退出\n        }\n    }\n}', 5, 1236, 0.00, '2026-04-13 02:07:57', '2026-04-13 02:07:57', 0);
INSERT INTO `problem_submission` VALUES (129, 3, 1, 'java', 'import java.util.ArrayList;\nimport java.util.List;\nimport java.util.Scanner;\n\npublic class Solution {\n\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 读取一行输入以模拟正常流程\n        if (scanner.hasNextLine()) {\n            String line = scanner.nextLine();\n            \n            Solution sol = new Solution();\n            sol.memoryLeakTest();\n        }\n    }\n\n    /**\n     * 核心算法：无限申请堆内存\n     */\n    public void memoryLeakTest() {\n        // 声明一个集合用于持有内存引用，防止 GC 回收\n        List<byte[]> memoryHog = new ArrayList<>();\n        \n        try {\n            while (true) {\n                // 每次循环申请 1MB 的字节数组\n                memoryHog.add(new byte[1024 * 1024]);\n            }\n        }\n    }\n}', 5, 785, 0.00, '2026-04-13 02:08:41', '2026-04-13 02:08:41', 0);
INSERT INTO `problem_submission` VALUES (130, 3, 1, 'java', 'import java.util.Scanner;\n\npublic class Solution {\n\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 读取一行输入以模拟正常流程，防止因缺少输入直接判错 (RE或WA)\n        if (scanner.hasNextLine()) {\n            String line = scanner.nextLine();\n            \n            Solution sol = new Solution();\n            sol.infiniteLoopTest();\n        }\n    }\n\n    /**\n     * 核心算法：纯 CPU 死循环\n     */\n    public void infiniteLoopTest() {\n        long counter = 0;\n        // 使用死循环疯狂占用 CPU 资源\n        while (true) {\n            counter++;\n            // 加上一些无意义的计算防止被编译器优化掉 (JIT Optimization)\n            if (counter < 0) {\n                counter = 0;\n            }\n        }\n    }\n}', 3, 3000, 0.00, '2026-04-13 02:08:57', '2026-04-13 02:08:57', 0);
INSERT INTO `problem_submission` VALUES (131, 3, 1, 'java', 'import java.util.ArrayList;\nimport java.util.List;\nimport java.util.Scanner;\n\npublic class Solution {\n\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        // 模拟正常 I/O\n        if (scanner.hasNextLine()) {\n            scanner.nextLine();\n        }\n        \n        // 大块申请，绕过 GC 优化\n        List<Object> list = new ArrayList<>();\n        \n        // 以 64MB 为单位申请内存\n        while (true) {\n            list.add(new byte[64 * 1024 * 1024]);\n        }\n    }\n}', 2, 1350, 0.00, '2026-04-13 02:22:39', '2026-04-13 02:22:39', 0);
INSERT INTO `problem_submission` VALUES (132, 3, 1, 'java', 'import java.util.ArrayList;\nimport java.util.List;\nimport java.util.Scanner;\n\npublic class Solution {\n\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        // 模拟正常 I/O\n        if (scanner.hasNextLine()) {\n            scanner.nextLine();\n        }\n        \n        // 大块申请，绕过 GC 优化\n        List<Object> list = new ArrayList<>();\n        \n        // 以 64MB 为单位申请内存\n        while (true) {\n            list.add(new byte[64 * 1024 * 1024]);\n        }\n    }\n}', 5, 1243, 0.00, '2026-04-13 02:23:14', '2026-04-13 02:23:14', 0);
INSERT INTO `problem_submission` VALUES (133, 3, 1, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public int[] solve(int[] nums, int target) {\n        Map<Integer, Integer> map = new HashMap<>();\n        for (int i = 0; i < nums.length; i++) {\n            int complement = target - nums[i];\n            if (map.containsKey(complement)) {\n                return new int[] { map.get(complement), i };\n            }\n            map.put(nums[i], i);\n        }\n        return new int[0];\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        // 假设输入格式示例：\n        // [2,7,11,15]\n        // 9\n        if (scanner.hasNextLine()) {\n            // 1. 读取并解析输入数据\n            String line = scanner.nextLine().trim();\n            // 去除前后方括号\n            line = line.replace(\"[\", \"\").replace(\"]\", \"\");\n            String[] parts = line.split(\",\");\n            int[] nums = new int[parts.length];\n            for (int i = 0; i < parts.length; i++) {\n                nums[i] = Integer.parseInt(parts[i].trim());\n            }\n            \n            int target = Integer.parseInt(scanner.nextLine().trim());\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            int[] result = sol.solve(nums, target);\n            \n            // 3. 按照题目要求的格式打印输出\n            if (result.length == 2) {\n                System.out.println(\"[\" + result[0] + \",\" + result[1] + \"]\");\n            } else {\n                System.out.println(\"[]\");\n            }\n        }\n        scanner.close();\n    }\n}', 1, 2969, 0.00, '2026-05-07 01:24:05', '2026-05-07 01:24:05', 0);
INSERT INTO `problem_submission` VALUES (134, 3, 2, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public int solve(int n) {\n        if (n <= 2) {\n            return n;\n        }\n        \n        int prev1 = 1; // 相当于 dp[i-2]\n        int prev2 = 2; // 相当于 dp[i-1]\n        int current = 0; // 相当于 dp[i]\n        \n        for (int i = 3; i <= n; i++) {\n            current = prev1 + prev2;\n            prev1 = prev2;\n            prev2 = current;\n        }\n        \n        return current;\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        if (scanner.hasNextInt()) {\n            // 1. 读取并解析输入数据\n            int n = scanner.nextInt();\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            int result = sol.solve(n);\n            \n            // 3. 按照题目要求的格式打印输出\n            System.out.println(result);\n        }\n        \n        scanner.close();\n    }\n}', 1, 4090, 0.00, '2026-05-07 11:40:29', '2026-05-07 11:40:29', 0);
