INSERT INTO `problem_submission` VALUES (144, 3, 2, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public int solve(int n) {\n        if (n <= 2) {\n            return n;\n        }\n        \n        int prev1 = 1; // 相当于 dp[i-2]\n        int prev2 = 2; // 相当于 dp[i-1]\n        int current = 0; // 相当于 dp[i]\n        \n        for (int i = 3; i <= n; i++) {\n            current = prev1 + prev2;\n            prev1 = prev2;\n            prev2 = current;\n        }\n        \n        return current;\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        if (scanner.hasNextInt()) {\n            // 1. 读取并解析输入数据\n            int n = scanner.nextInt();\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            int result = sol.solve(n);\n            \n            // 3. 按照题目要求的格式打印输出\n            System.out.println(result);\n        }\n        \n        scanner.close();\n    }\n}', 1, 3898, 0.00, '2026-05-08 20:18:30', '2026-05-08 20:18:30', 0);
INSERT INTO `problem_submission` VALUES (145, 3, 3, 'java', 'import java.util.*;\nimport java.io.*;\n\npublic class Solution {\n\n    /**\n     * 核心算法逻辑写在这里\n     */\n    public boolean solve(String s) {\n        Stack<Character> stack = new Stack<>();\n        for (char c : s.toCharArray()) {\n            // 遇到左括号入栈\n            if (c == \'(\' || c == \'{\' || c == \'[\') {\n                stack.push(c);\n            } \n            // 遇到右括号进行匹配\n            else {\n                if (stack.isEmpty()) {\n                    return false;\n                }\n                char top = stack.pop();\n                if ((c == \')\' && top != \'(\') ||\n                    (c == \'}\' && top != \'{\') ||\n                    (c == \']\' && top != \'[\')) {\n                    return false;\n                }\n            }\n        }\n        // 最终检查栈是否为空\n        return stack.isEmpty();\n    }\n\n    /**\n     * CodeNexus ACM 模式程序入口\n     * 请在此处解析标准输入 (Standard Input) 并打印标准输出 (Standard Output)\n     */\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        if (scanner.hasNextLine()) {\n            // 1. 读取并解析输入数据\n            String s = scanner.nextLine().trim();\n            \n            // 处理输入可能包含的双引号，注意此处已在 SQL 中将 Java 的 \\\" 转义为 \\\\\\\"\n            if (s.startsWith(\"\\\"\") && s.endsWith(\"\\\"\")) {\n                s = s.substring(1, s.length() - 1);\n            }\n            \n            // 2. 实例化并调用核心算法\n            Solution sol = new Solution();\n            boolean result = sol.solve(s);\n            \n            // 3. 按照题目要求的格式打印输出\n            System.out.println(result);\n        }\n        \n        scanner.close();\n    }\n}', 1, 4835, 0.00, '2026-05-08 20:19:58', '2026-05-08 20:19:58', 0);
