-- ----------------------------
-- Table structure for arena_room
-- ----------------------------
DROP TABLE IF EXISTS `arena_room`;
CREATE TABLE `arena_room`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '物理主键',
  `room_code` varchar(8) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '房间短码 (如: A8X9P2)，用于前端分享与URL展示',
  `room_type` tinyint NOT NULL COMMENT '房间类型: 1-私人邀请, 2-公开大厅, 3-天梯匹配',
  `password` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '房间密码 (仅私人/公开房间有效，匹配房间为空)',
  `problem_id` bigint NULL DEFAULT NULL COMMENT '题目ID (如果是匹配模式，由系统随选填入)',
  `status` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'WAITING' COMMENT '状态: WAITING(等待中), BATTLING(战斗中), FINISHED(已结束), DISMISSED(已解散)',
  `creator_id` bigint NOT NULL COMMENT '房主ID (如果是天梯匹配，则为系统分配的先手玩家或系统ID)',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除(0-未删除, 1-已删除)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_room_code`(`room_code` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 210 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '竞技场房间表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of arena_room
-- ----------------------------

-- ----------------------------
-- Table structure for arena_room_user
-- ----------------------------
DROP TABLE IF EXISTS `arena_room_user`;
CREATE TABLE `arena_room_user`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '物理主键',
  `room_id` bigint NOT NULL COMMENT '关联 arena_room 的物理主键',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `is_creator` tinyint NOT NULL DEFAULT 0 COMMENT '是否为房主 (0-否, 1-是)',
  `status` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'JOINED' COMMENT '状态: JOINED(已加入), READY(已准备), BATTLING(战斗中), ESCAPED(逃跑)',
  `result` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '战斗结果: WIN(胜), LOSE(负), DRAW(平局)',
  `score_change` int NULL DEFAULT 0 COMMENT '天梯分变动 (+/-)',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '加入时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_room_user`(`room_id` ASC, `user_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 363 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '竞技场房间用户关联表' ROW_FORMAT = Dynamic;

