  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_folder_problem`(`folder_id` ASC, `problem_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE
