-- ----------------------------
-- Table structure for problem
-- ----------------------------
DROP TABLE IF EXISTS `problem`;
CREATE TABLE `problem`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键, 题目ID',
  `display_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '展示用ID(如 P-1001)',
  `title` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '题目标题',
  `description` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '题目描述 (Markdown格式)',
  `difficulty` tinyint NOT NULL DEFAULT 1 COMMENT '难度: 1-Easy, 2-Medium, 3-Hard',
  `tags` json NULL COMMENT '标签列表 (JSON数组, 如 [\"动态规划\", \"数组\"])',
  `examples` json NULL COMMENT '测试用例示例(JSON数组，包含 input, output, explanation)',
  `time_limit` int NOT NULL DEFAULT 1000 COMMENT '时间限制 (单位: ms)',
  `memory_limit` int NOT NULL DEFAULT 256 COMMENT '空间限制 (单位: MB)',
  `submit_num` int NOT NULL DEFAULT 0 COMMENT '总提交次数',
  `accepted_num` int NOT NULL DEFAULT 0 COMMENT '总通过次数',
  `status` int NULL DEFAULT 1 COMMENT '0-草稿,1-已上架,2-已下架',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除(0-未删除, 1-已删除)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_display_id`(`display_id` ASC) USING BTREE,
  INDEX `idx_difficulty`(`difficulty` ASC) USING BTREE,
  INDEX `idx_tags`((cast(`tags` as char(32) array))) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 25 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '题库基础信息表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of problem
-- ----------------------------

-- ----------------------------
-- Table structure for problem_solution
-- ----------------------------
DROP TABLE IF EXISTS `problem_solution`;
CREATE TABLE `problem_solution`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `problem_id` bigint NOT NULL COMMENT '关联题目ID',
  `author_id` bigint NOT NULL COMMENT '题解作者ID (关联 user 表)',
  `title` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '题解标题',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '题解正文(富文本/Markdown)',
  `code` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '题解核心代码',
  `view_count` int NOT NULL DEFAULT 0 COMMENT '阅读量',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除(0-未删除, 1-已删除)',
  `is_official` tinyint NULL DEFAULT 0 COMMENT '是否官方题解(0-否 1-是)',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 29 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '题目官方题解表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of problem_solution
-- ----------------------------

-- ----------------------------
-- Table structure for problem_submission
-- ----------------------------
DROP TABLE IF EXISTS `problem_submission`;
CREATE TABLE `problem_submission`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NOT NULL COMMENT '提交用户ID',
  `problem_id` bigint NOT NULL COMMENT '关联题目ID',
  `language` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '编程语言(如 java, cpp, typescript)',
  `code` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '提交的完整代码',
  `status` tinyint NOT NULL COMMENT '评测状态: 0-PENDING, 1-AC, 2-WA, 3-TLE, 4-MLE, 5-RE, 6-CE',
  `time_cost` int NULL DEFAULT NULL COMMENT '运行耗时(单位: ms)',
  `memory_cost` decimal(8, 2) NULL DEFAULT NULL COMMENT '内存消耗(单位: MB)',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间(即提交时间)',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除(0-未删除, 1-已删除)',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_problem`(`user_id` ASC, `problem_id` ASC) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 153 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户题目提交记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of problem_submission
-- ----------------------------

-- ----------------------------
-- Table structure for problem_testcase
-- ----------------------------
DROP TABLE IF EXISTS `problem_testcase`;
CREATE TABLE `problem_testcase`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键, 测试用例/检查点ID',
  `problem_id` bigint NOT NULL COMMENT '关联题目ID',
  `input_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '输入数据 (JSON 字符串或多行纯文本格式)',
  `expected_output` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '预期输出 (用于沙箱结果严格比对)',
  `is_public` tinyint NOT NULL DEFAULT 0 COMMENT '是否为公开示例: 0-隐藏测试用例(Hidden), 1-公开示例(Example)',
  `sort_order` int NOT NULL DEFAULT 0 COMMENT '执行顺序与展示排序权重',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除(0-未删除, 1-已删除)',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_problem_id`(`problem_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 59 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '题目测试用例检查点表' ROW_FORMAT = DYNAMIC;

